    target->reset();
    observer1->reset();
    observer2->reset();

    // 4. Notify target
    target->valueChanged(true);

    // 5. Verify both observers were notified
    bool chain_worked = (observer1->getCallCount() > 0) && (observer2->getCallCount() > 0);

    // 6. Calculate total call count
    int total_calls = observer1->getCallCount() + observer2->getCallCount();

