  EXPECT_EQ(snapshot.initialValue, initialValue * 2);
  EXPECT_EQ(snapshot.afterUpdate, updatedValue * 2);
  EXPECT_EQ(snapshot.afterSourceClose, snapshot.afterUpdate);
}

