namespace test_reaction {

class TrackingFieldNode : public reaction::ObserverNode {
public:
    explicit TrackingFieldNode(std::string name) : m_name(std::move(name)) {}

    void valueChanged(bool changed = true) override {
        if (changed) {
            m_notifications++;
        }
    }

    int notifications() const {
        return m_notifications;
    }

    void clear() {
        m_notifications = 0;
    }

private:
    std::string m_name;
    int m_notifications = 0;
};

struct FieldGraphCleanupResult {
    bool notifiedBeforeDelete;
    bool notifiedAfterDelete;
};

inline FieldGraphCleanupResult test_field_graph_cleanup(uint64_t objectId) {
    FieldGraphCleanupResult result{false, false};

    // 1. Create owner and field TrackingFieldNode instances
    auto owner = std::make_shared<TrackingFieldNode>("owner");
    auto field = std::make_shared<TrackingFieldNode>("field");

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    // Nodes are automatically registered when created as shared_ptr and inherit from ObserverNode

    // 4. Get field graph instance
    auto& fieldGraph = reaction::FieldGraph::getInstance();

    // 5. Register field nodes under object ID
    fieldGraph.registerField(objectId, field);

    // 6. Bind field to owner
    fieldGraph.bindField(objectId, owner);

    // 7. Trigger notification on field
    field->updateObservers();

    // 8. Check if owner was notified before delete
    result.notifiedBeforeDelete = (owner->notifications() > 0);

    // 9. Clear owner notification count
    owner->clear();

    // 10. Clear dependencies on owner
    observerGraph.removeObserver(owner);

    // 11. Remove field mappings for object ID
    fieldGraph.removeFieldMapping(objectId);

    // 12. Attempt to bind field again
    fieldGraph.bindField(objectId, owner);

    // 13. Trigger notification on field again
    field->updateObservers();

    // 14. Check if owner was notified after delete
    result.notifiedAfterDelete = (owner->notifications() > 0);

    // 15. Close nodes
    // Shared pointers will automatically clean up when they go out of scope

    return result;
}

}  // namespace test_reaction
```

This implementation:

1. Creates `TrackingFieldNode` instances for owner and field
2. Gets the observer graph singleton instance
3. Nodes are automatically registered when created as shared pointers
4. Gets the field graph singleton instance
5. Registers the field node under the specified object ID
6. Binds the field to the owner using the field graph
7. Triggers a notification on the field node
8. Checks if owner received notifications before cleanup
9. Clears the owner's notification count
10. Clears dependencies by removing the owner from observer graph
11. Removes field mappings for the object ID
12. Attempts to bind again (should have no effect after cleanup)
13. Triggers another notification on the field
14. Checks if owner received notifications after cleanup
15. Nodes are automatically cleaned up when shared pointers go out of scope
16. Returns the result structure with both notification states

The `TrackingFieldNode` implementation tracks notifications through the `valueChanged` method override and provides methods to check and clear the notification count.

