#include <reaction/memory/stack_monitor.h>

namespace test_reaction {

struct StackLimitSnapshot {
    reaction::memory::StackMonitor::UsageStats statsBeforeGuard;
    reaction::memory::StackMonitor::UsageStats statsAfterGuard;
    bool templateAllocationAllowed;
    bool runtimeAllocationAllowed;
    bool guardHeld;
    bool allocationBlockedWhileGuardHeld;
};

StackLimitSnapshot test_stack_monitor_limits() {
    using namespace reaction::memory;

    StackLimitSnapshot snapshot{};

    // 1. Enable monitoring
    StackMonitor::enableMonitoring();

    // 2. Initialize stack monitor
    StackMonitor::init();

    // 3. Get usage statistics before guard
    snapshot.statsBeforeGuard = StackMonitor::getUsageStats();

    // 4. Check if template allocation is allowed
    snapshot.templateAllocationAllowed = StackMonitor::isTemplateAllocationAllowed();

    // 5. Check if runtime allocation is allowed
    snapshot.runtimeAllocationAllowed = StackMonitor::isRuntimeAllocationAllowed();

    // 6. Create large StackGuard instance
    snapshot.guardHeld = false;
    snapshot.allocationBlockedWhileGuardHeld = false;

    try {
        // Create a large guard to test limits
        StackMonitor::StackGuard<1024 * 1024> largeGuard; // 1MB guard

        // 7. Check if guard succeeded
        snapshot.guardHeld = true;

        // 8. Check if allocation blocked while guard is held
        // Try to create another guard to see if allocation is blocked
        try {
            StackMonitor::StackGuard<512> smallGuard; // Small guard
            // If we get here, allocation was not blocked
            snapshot.allocationBlockedWhileGuardHeld = false;
        } catch (const std::exception&) {
            // Allocation was blocked
            snapshot.allocationBlockedWhileGuardHeld = true;
        }

        // 9. Get usage statistics after guard
        snapshot.statsAfterGuard = StackMonitor::getUsageStats();

    } catch (const std::exception&) {
        // Guard creation failed
        snapshot.guardHeld = false;
        snapshot.allocationBlockedWhileGuardHeld = false;

        // Still get usage statistics after the failed guard attempt
        snapshot.statsAfterGuard = StackMonitor::getUsageStats();
    }

    return snapshot;
}

}  // namespace test_reaction
```

