    // Get initial cache statistics
    auto initialStats = cache.getStats();
    std::size_t entriesBefore = cache.size();

    // Perform initial lookup (should miss)
    auto firstLookup = cache.lookup(42);
    bool firstLookupWasMiss = (firstLookup == nullptr);

    // Insert value into cache
