    bool secondLookupWasHit = (secondLookup != nullptr);

    // Get cache statistics after insertion
    auto statsAfterInsert = cache.getStats();
    std::size_t entriesAfterInsert = cache.size();

    // Invalidate all cache entries
    cache.invalidateAll();

    // Trigger cleanup
    cache.cleanup();

    // Get cache statistics after invalidation
    auto statsAfterInvalidate = cache.getStats();
    std::size_t entriesAfterInvalidate = cache.size();

    // Calculate hit ratio
