    double hitRatio = totalAccesses > 0 ? 
        static_cast<double>(statsAfterInsert.hitCount) / totalAccesses : 0.0;

    // Return generic cache stats snapshot
    return GenericCacheStatsSnapshot{
        entriesBefore,
        entriesAfterInsert,
        entriesAfterInvalidate,
        statsAfterInsert.hitCount,
        statsAfterInsert.missCount,
        hitRatio,
        firstLookupWasMiss,
        secondLookupWasHit
    };
}

}  // namespace test_reaction
